# =========================
# Firebase 初始化
# =========================
import firebase_admin
from firebase_admin import credentials, db as firebase_db

@st.cache_resource
def init_firebase():
    if firebase_admin._apps:
        return firebase_admin.get_app()
    s = st.secrets["firebase"]
    cert = {
        "type":                        s["type"],
        "project_id":                  s["project_id"],
        "private_key_id":              s["private_key_id"],
        "private_key":                 s["private_key"].replace("\\n", "\n"),
        "client_email":                s["client_email"],
        "client_id":                   s["client_id"],
        "auth_uri":                    s["auth_uri"],
        "token_uri":                   s["token_uri"],
        "client_x509_cert_url":        s.get("client_x509_cert_url", ""),
        "auth_provider_x509_cert_url": s.get("auth_provider_x509_cert_url", ""),
    }
    cred = credentials.Certificate(cert)
    return firebase_admin.initialize_app(cred, {"databaseURL": s["database_url"]})

# =========================
# Firebase CRUD（專案）
# =========================
def save_project(data: dict) -> str:
    init_firebase()
    new_ref = firebase_db.reference("projects").push(data)
    load_projects_cached.clear()
    return new_ref.key

def update_project(fb_key: str, data: dict):
    init_firebase()
    firebase_db.reference(f"projects/{fb_key}").update(data)
    load_projects_cached.clear()

def delete_project(fb_key: str):
    init_firebase()
    firebase_db.reference(f"projects/{fb_key}").delete()
    load_projects_cached.clear()

@st.cache_data(ttl=30)
def load_projects_cached() -> list:
    init_firebase()
    data = firebase_db.reference("projects").get()
    if not data:
        return []
    result = []
    for k, v in data.items():
        v["_fb_key"] = k
        result.append(v)
    return sorted(result, key=lambda x: x.get("recvdate", ""), reverse=True)

# =========================
# ★ 訪客計數器（依 SITE_ID 獨立命名空間）
# Firebase 路徑：
#   visitors/{SITE_ID}/total
#   visitors/{SITE_ID}/daily/YYYY-MM-DD
# =========================
def _vref(path: str = ""):
    base = f"visitors/{SITE_ID}"
    return firebase_db.reference(f"{base}/{path}" if path else base)

def increment_visitor():
    init_firebase()
    _vref("total").transaction(lambda c: (c or 0) + 1)

def increment_daily_visitor():
    init_firebase()
    _vref(f"daily/{date.today().strftime('%Y-%m-%d')}").transaction(lambda c: (c or 0) + 1)

def get_visitor_count() -> int:
    init_firebase()
    return _vref("total").get() or 0

def get_today_visitor_count() -> int:
    init_firebase()
    return _vref(f"daily/{date.today().strftime('%Y-%m-%d')}").get() or 0

def get_month_visitor_count() -> int:
    init_firebase()
    daily = _vref("daily").get() or {}
    ym = date.today().strftime("%Y-%m")
    return sum(v for k, v in daily.items() if k.startswith(ym))

# =========================
# ZIP 產生
# =========================
def folder_name(d: dict) -> str:
    date_str = (d.get("recvdate") or "00000000").replace("-", "")
    subject  = (d.get("subject") or "無主旨")[:20]
    for ch in r'/\\:*?"<>|':
        subject = subject.replace(ch, "")
    return f"{date_str}_{subject}"

